import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, Marker, Popup, Polyline } from "react-leaflet";
import L from "leaflet";

const pinkIcon = new L.Icon({
  iconUrl:
    "https://cdn-icons-png.flaticon.com/512/684/684908.png",
  iconSize: [35, 35]
});

function GoogleMapView({ destination }) {

  const [position, setPosition] = useState(null);
  const [route, setRoute] = useState([]);

  useEffect(() => {

    navigator.geolocation.watchPosition((pos) => {

      const lat = pos.coords.latitude;
      const lon = pos.coords.longitude;

      setPosition([lat, lon]);
      setRoute(prev => [...prev, [lat, lon]]);

    });

  }, []);

  return (

    <MapContainer
      center={position || [28.6139, 77.2090]}
      zoom={14}
      style={{ height: "400px", width: "100%" }}
    >

      <TileLayer
        url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
      />

      {position && (

        <Marker position={position} icon={pinkIcon}>
          <Popup>Live Location</Popup>
        </Marker>

      )}

      {route.length > 1 && (

        <Polyline positions={route} color="pink" />

      )}

    </MapContainer>

  );

}

export default GoogleMapView;
